#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long ans = 0, x;
        for (int i = 0; i < N; ++i) {
            scanf("%lld", &x);
            ans ^= x;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

